class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows loading objects from
    a whitelist of safe modules and classes (primarily sklearn and numpy).
    This prevents arbitrary code execution via malicious pickle files.
    """

    def find_class(self, module: str, name: str) -> Any:
        # Block any obviously dangerous names
        if name in BLOCKED_NAMES or module in BLOCKED_NAMES:
            raise pickle.UnpicklingError(
                f"Blocked unsafe class/module: {module}.{name}"
            )

        # Check if the specific (module, name) pair is explicitly allowed
        if (module, name) in ALLOWED_GLOBALS:
            return super().find_class(module, name)

        # Check if the module is in our allowed module prefixes
        module_allowed = False
        for allowed_mod in ALLOWED_MODULES:
            if module == allowed_mod or module.startswith(allowed_mod + "."):
                module_allowed = True
                break

        if not module_allowed:
            raise pickle.UnpicklingError(
                f"Forbidden module in pickle: {module}.{name}. "
                f"Only scikit-learn and numpy models are supported."
            )

        # Even within allowed modules, block dunders except __init__ and common ones
        if name.startswith("__") and name.endswith("__"):
            if name not in ("__init__", "__new__", "__dict__", "__setstate__", "__getstate__"):
                raise pickle.UnpicklingError(
                    f"Blocked dunder method: {module}.{name}"
                )

        return super().find_class(module, name)


def safe_pickle_load(data: bytes) -> Any:
    """Safely load a pickle file using the restricted unpickler."""
    return RestrictedUnpickler(io.BytesIO(data)).load()


# --- Additional pickle safety: check for suspicious opcodes ---

def scan_pickle_opcodes(data: bytes) -> list:
    """Scan pickle bytecode for suspicious opcodes that might indicate malicious content."""
    suspicious = []

    # Check for REDUCE opcode combined with suspicious patterns
    # These are heuristic checks on the raw bytes
    dangerous_strings = [
        b"os.system", b"os.popen", b"subprocess",
        b"__import__", b"eval(", b"exec(",
        b"builtins.eval", b"builtins.exec",
        b"commands.getoutput", b"pty.spawn",
        b"shutil.rmtree", b"/bin/sh", b"/bin/bash",
        b"cmd.exe", b"powershell",
    ]

    for pattern in dangerous_strings:
        if pattern in data:
            suspicious.append(f"Suspicious pattern found: {pattern.decode('utf-8', errors='replace')}")

    return suspicious


