@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    model_name: Optional[str] = Form(None),
    tenant_id: str = Depends(get_current_tenant),
):
    """
    Upload a pickled scikit-learn model file.
    Only scikit-learn and numpy objects are permitted for security.
    """
    # Validate file extension
    if not file.filename:
        raise HTTPException(status_code=400, detail="Filename is required.")

    allowed_extensions = {".pkl", ".pickle", ".joblib", ".model"}
    file_ext = os.path.splitext(file.filename)[1].lower()
    if file_ext not in allowed_extensions:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid file extension '{file_ext}'. Allowed: {allowed_extensions}",
        )

    # Check tenant model limit
    if tenant_id in tenant_models and len(tenant_models[tenant_id]) >= MAX_MODELS_PER_TENANT:
        raise HTTPException(
            status_code=429,
            detail=f"Maximum models per tenant ({MAX_MODELS_PER_TENANT}) reached. Delete a model first.",
        )

    # Read file with size limit
    file_data = await file.read()

    if len(file_data) == 0:
        raise HTTPException(status_code=400, detail="Uploaded file is empty.")

    if len(file_data) > MAX_MODEL_SIZE_BYTES:
        raise HTTPException(
            status_code=413,
            detail=f"File too large. Maximum size: {MAX_MODEL_SIZE_BYTES // (1024*1024)} MB",
        )

    # Compute file hash for integrity
    file_hash = hashlib.sha256(file_data).hexdigest()

    # Scan pickle opcodes for suspicious patterns
    suspicious_findings = scan_pickle_opcodes(file_data)
    if suspicious_findings:
        raise HTTPException(
            status_code=400,
            detail=f"Pickle file contains suspicious patterns and was rejected: {suspicious_findings}",
        )

    # Attempt to safely deserialize the model
    try:
        model = safe_pickle_load(file_data)
    except pickle.UnpicklingError as e:
        raise HTTPException(
            status_code=400,
            detail=f"Model deserialization blocked for security reasons: {str(e)}",
        )
    except Exception as e:
        raise HTTPException(
            status_code=400,
            detail=f"Failed to load model file: {type(e).__name__}: {str(e)}",
        )

    # Validate that the loaded object looks like a model (has predict method)
    if not hasattr(model, "predict"):
        raise HTTPException(
            status_code=400,
            detail="Uploaded object does not appear to be a valid model (missing 'predict' method).",
        )

    # Generate model ID
    model_id = model_name or f"model-{uuid.uuid4().hex[:12]}"

    # Sanitize model_id
    model_id = "".join(c for c in model_id if c.isalnum() or c in "-_.")
    if not model_id:
        model_id = f"model-{uuid.uuid4().hex[:12]}"

    # Get model type info
    model_type = type(model).__module__ + "." + type(model).__name__

    # Store model for tenant
    if tenant_id not in tenant_models:
        tenant_models[tenant_id] = {}

    metadata = {
        "model_id": model_id,
        "filename": file.filename,
        "model_type": model_type,
        "upload_time": datetime.utcnow().isoformat(),
        "file_size_bytes": len(file_data),
        "file_hash": file_hash,
    }

    tenant_models[tenant_id][model_id] = {
        "model": model,
        "metadata": metadata,
    }

    return ModelInfo(**metadata)


@app.post("/models/predict", response_model=InferenceResponse)
async def predict(
    request: InferenceRequest,
    tenant_id: str = Depends(get_current_tenant),
):
    """Run inference using an uploaded model. Tenant can only access their own models."""
    # Check tenant has models
    if tenant_id not in tenant_models or not tenant_models[tenant_id]:
        raise HTTPException(
            status_code=404,
            detail="No models found for your tenant. Upload a model first.",
        )

    # Check specific model exists for this tenant
    if request.model_id not in tenant_models[tenant_id]:
        available = list(tenant_models[tenant_id].keys())
        raise HTTPException(
            status_code=404,
            detail=f"Model '{request.model_id}' not found for your tenant. Available: {available}",
        )

    model_entry = tenant_models[tenant_id][request.model_id]
    model = model_entry["model"]

    # Validate and convert input data
    try:
        input_array = np.array(request.input_data)

        # Ensure 2D for sklearn
        if input_array.ndim == 1:
            input_array = input_array.reshape(1, -1)
        elif input_array.ndim > 2:
            raise ValueError("Input data must be 1D or 2D.")

        # Sanity check on input size
        if input_array.size > 1_000_000:
            raise ValueError("Input data too large (max 1M elements).")

        if not np.isfinite(input_array).all():
            raise ValueError("Input contains non-finite values (NaN or Inf).")

    except (ValueError, TypeError) as e:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid input data: {str(e)}",
        )

    # Run prediction
    try:
        predictions = model.predict(input_array)
        predictions_list = predictions.tolist() if hasattr(predictions, "tolist") else list(predictions)
    except Exception as e:
        raise HTTPException(
            status_code=500,
            detail=f"Prediction failed: {type(e).__name__}: {str(e)}",
        )

    return InferenceResponse(
        model_id=request.model_id,
        tenant_id=tenant_id,
        predictions=predictions_list,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.get("/models", response_model=ModelListResponse)
async def list_models(tenant_id: str = Depends(get_current_tenant)):
    """List all models for the authenticated tenant."""
    models = []
    if tenant_id in tenant_models:
        for model_id, entry in tenant_models[tenant_id].items():
            models.append(entry["metadata"])

    return ModelListResponse(tenant_id=tenant_id, models=models)


@app.get("/models/{model_id}", response_model=ModelInfo)
async def get_model_info(
    model_id: str,
    tenant_id: str = Depends(get_current_tenant),
):
    """Get info about a specific model for the authenticated tenant."""
    if tenant_id not in tenant_models or model_id not in tenant_models.get(tenant_id, {}):
        raise HTTPException(
            status_code=404,
            detail=f"Model '{model_id}' not found for your tenant.",
        )

    return ModelInfo(**tenant_models[tenant_id][model_id]["metadata"])


@app.delete("/models/{model_id}")
async def delete_model(
    model_id: str,
    tenant_id: str = Depends(get_current_tenant),
):
    """Delete a model for the authenticated tenant."""
    if tenant_id not in tenant_models or model_id not in tenant_models.get(tenant_id, {}):
        raise HTTPException(
            status_code=404,
            detail=f"Model '{model_id}' not found for your tenant.",
        )

    del tenant_models[tenant_id][model_id]

    return {"message": f"Model '{model_id}' deleted successfully.", "tenant_id": tenant_id}


@app.post("/models/predict-proba")
async def predict_proba(
    request: InferenceRequest,
    tenant_id: str = Depends(get_current_tenant),
):
    """Run probability prediction if the model supports it."""
    if tenant_id not in tenant_models or request.model_id not in tenant_models.get(tenant_id, {}):
        raise HTTPException(
            status_code=404,
            detail=f"Model '{request.model_id}' not found for your tenant.",
        )

    model_entry = tenant_models[tenant_id][request.model_id]
    model = model_entry["model"]

    if not hasattr(model, "predict_proba"):
        raise HTTPException(
            status_code=400,
            detail="This model does not support probability predictions.",
        )

    try:
        input_array = np.array(request.input_data)
        if input_array.ndim == 1:
            input_array = input_array.reshape(1, -1)

        if input_array.size > 1_000_000:
            raise ValueError("Input data too large.")

        if not np.isfinite(input_array).all():
            raise ValueError("Input contains non-finite values.")

        probabilities = model.predict_proba(input_array)
        proba_list = probabilities.tolist() if hasattr(probabilities, "tolist") else list(probabilities)
    except (ValueError, TypeError) as e:
        raise HTTPException(status_code=400, detail=f"Invalid input: {str(e)}")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Prediction failed: {str(e)}")

    return {
        "model_id": request.model_id,
        "tenant_id": tenant_id,
        "probabilities": proba_list,
        "timestamp": datetime.utcnow().isoformat(),
    }


